      CR = CR.intersectWith(*Range);
  }

  if (CR.isFullSet() || CR.isEmptySet())
    return false;

  const APInt &Lower = CR.getLower();
  const APInt &Upper = CR.getUpper();

  // Cases is sorted in descending order (from casesAreContiguous).
  // The complement within [Lower, Upper) is contiguous iff there's exactly
  // one gap between consecutive elements (including the bounds).

  unsigned NumGaps = 0;
  APInt GapStart(BitWidth, 0), GapEnd(BitWidth, 0);

