/// Check if the complement of Cases within the possible values of the switch
/// condition forms a contiguous range. If so, populate Complement with the
/// values in the complement and return true.
static bool getContiguousComplement(const SwitchInst &SI,
                                    SmallVectorImpl<ConstantInt *> &Cases,
                                    SmallVectorImpl<ConstantInt *> &Complement) {
  assert(Cases.size() >= 1);

  const Value *Cond = SI.getCondition();
  unsigned BitWidth = Cond->getType()->getScalarSizeInBits();

  // Get the range of possible values for the condition.
  ConstantRange CR = ConstantRange::getFull(BitWidth);

  if (const auto *Arg = dyn_cast<Argument>(Cond)) {
    if (std::optional<ConstantRange> Range = Arg->getRange())
      CR = CR.intersectWith(*Range);
  }

  if (CR.isFullSet() || CR.isEmptySet())
    return false;

  const APInt &Lower = CR.getLower();
  const APInt &Upper = CR.getUpper();

  // Cases is sorted in descending order (from casesAreContiguous).
  // The complement within [Lower, Upper) is contiguous iff there's exactly
  // one gap between consecutive elements (including the bounds).

  unsigned NumGaps = 0;
  APInt GapStart(BitWidth, 0), GapEnd(BitWidth, 0);

  // Gap between Upper-1 and Cases[0] (the largest case).
  APInt LargestInRange = Upper - 1;
  if (Cases.front()->getValue() != LargestInRange) {
    NumGaps++;
    GapStart = Cases[0]->getValue() + 1;
    GapEnd = Upper;
  }

  for (size_t I = 1; I < Cases.size(); ++I) {
    if (Cases[I - 1]->getValue() != Cases[I]->getValue() + 1) {
      NumGaps++;
      if (NumGaps == 1) {
        GapStart = Cases[I]->getValue() + 1;
        GapEnd = Cases[I - 1]->getValue();
      }
    }
  }

  // Gap between Cases[last] (the smallest case) and Lower.
  if (Cases.back()->getValue() != Lower) {
    NumGaps++;
    if (NumGaps == 1) {
      GapStart = Lower;
      GapEnd = Cases.back()->getValue();
    }
  }

  if (NumGaps != 1)
    return false;

  // The gap should not wrap around.
  if (GapStart.uge(GapEnd))
    return false;

  // Check if the gap size is reasonable.
  uint64_t GapSize = (GapEnd - GapStart).getLimitedValue();
  if (GapSize > 256)
    return false;

  // Build the complement from the gap.
  for (APInt V = GapStart; V.ult(GapEnd); ++V)
    Complement.push_back(ConstantInt::get(Cond->getType(), V));

  return true;
}

